   128	// Select returns true if the metric matches according to the
   129	// namepass/namedrop, tagpass/tagdrop and metric filters.
   130	// The metric is not modified.
   131	func (f *Filter) Select(metric telegraf.Metric) (bool, error) {
   132		if !f.selectActive {
   133			return true, nil
   134		}
   135	
   136		if !f.shouldNamePass(metric.Name()) {
   137			return false, nil
   138		}
   139	
   140		if !f.shouldTagsPass(metric.TagList()) {
   141			return false, nil
   142		}
   143	
   144		if f.metricFilter != nil {
   145			result, _, err := f.metricFilter.Eval(map[string]interface{}{
   146				"name":   metric.Name(),
   147				"tags":   metric.Tags(),
   148				"fields": metric.Fields(),
   149				"time":   metric.Time(),
   150			})
   151			if err != nil {
   152				return true, err
   153			}
   154			if r, ok := result.Value().(bool); ok {
   155				return r, nil
   156			}
   157			return true, fmt.Errorf("invalid result type %T", result.Value())
   158		}
   159	
   160		return true, nil
   161	}
