   249		env, err := cel.NewEnv(
   250			cel.VariableDecls(
   251				decls.NewVariable("name", types.StringType),
   252				decls.NewVariable("tags", types.NewMapType(types.StringType, types.StringType)),
   253				decls.NewVariable("fields", types.NewMapType(types.StringType, types.DynType)),
   254				decls.NewVariable("time", types.TimestampType),
   255			),
   256			cel.Function(
   257				"now",
   258				cel.Overload("now", nil, cel.TimestampType),
   259				cel.SingletonFunctionBinding(func(_ ...ref.Val) ref.Val { return types.Timestamp{Time: time.Now()} }),
   260			),
   261			ext.Encoders(),
   262			ext.Math(),
   263			ext.Strings(),
   264		)
