   270		ast, issues := env.Compile(expression)
   271		if issues.Err() != nil {
   272			return issues.Err()
   273		}
   274		// Check if we got a boolean expression needed for filtering
   275		if ast.OutputType() != cel.BoolType {
   276			return errors.New("expression needs to return a boolean")
   277		}
   278	
   279		// Get the final program
   280		options := cel.EvalOptions(
   281			cel.OptOptimize,
   282		)
   283		f.metricFilter, err = env.Program(ast, options)
   284		return err
   285	}
