   287	func ShouldPassFilters(include, exclude filter.Filter, key string) bool {
   288		if include != nil && exclude != nil {
   289			return include.Match(key) && !exclude.Match(key)
   290		} else if include != nil {
   291			return include.Match(key)
   292		} else if exclude != nil {
   293			return !exclude.Match(key)
   294		}
   295		return true
   296	}
   297	
   298	func ShouldTagsPass(passFilters, dropFilters []TagFilter, tags []*telegraf.Tag) bool {
   299		pass := func(tpf []TagFilter) bool {
   300			for _, pat := range tpf {
   301				if pat.filter == nil {
   302					continue
   303				}
   304				for _, tag := range tags {
   305					if tag.Key == pat.Name {
   306						if pat.filter.Match(tag.Value) {
   307							return true
   308						}
   309					}
   310				}
   311			}
   312			return false
   313		}
   314	
   315		drop := func(tdf []TagFilter) bool {
   316			for _, pat := range tdf {
   317				if pat.filter == nil {
   318					continue
   319				}
   320				for _, tag := range tags {
   321					if tag.Key == pat.Name {
   322						if pat.filter.Match(tag.Value) {
   323							return false
   324						}
   325					}
   326				}
   327			}
   328			return true
   329		}
   330	
   331		// Add additional logic in case where both parameters are set.
   332		// see: https://github.com/influxdata/telegraf/issues/2860
   333		if passFilters != nil && dropFilters != nil {
   334			// return true only in case when tag pass and won't be dropped (true, true).
   335			// in case when the same tag should be passed and dropped it will be dropped (true, false).
