//go:build linux && amd64

package turbostat

import (
	"strings"
	"testing"

	"github.com/influxdata/telegraf/testutil"
)

func TestReproduceUsecError(t *testing.T) {
	// This test simulates what happens when a repeated header has different
	// whitespace, causing the exact string comparison (line == header) to fail.
	// The header row would then be processed as data, and the literal string
	// "usec" cannot be parsed as a float.

	header := "usec    Time_Of_Day_Seconds     Core    CPU"

	// Parse the header to create columns
	headerFields := strings.Fields(header)
	columns := make([]column, 0, len(headerFields))
	for _, s := range headerFields {
		columns = append(columns, createColumn(s))
	}

	// Simulate the header being processed as a data line (which happens when
	// the repeated header whitespace doesn't match exactly)
	headerValues := strings.Fields(header)
	var acc testutil.Accumulator
	err := processValues(&acc, columns, headerValues)
	if err == nil {
		t.Error("Expected an error when parsing header as data, but got none")
	} else {
		t.Logf("Got expected error: %v", err)
		// Verify it's the "usec" parse error
		if !strings.Contains(err.Error(), "usec") {
			t.Errorf("Expected error about 'usec', got: %v", err)
		}
	}
}

